const emails = $input.all();
let combined = '';

for (const email of emails) {
  const from = email.json.From || email.json.from || email.json.headers?.from || 'Unknown';
  const subject = email.json.Subject || email.json.subject || email.json.headers?.subject || 'No subject';
  const body = email.json.text || email.json.body || email.json.snippet || '';
  const cleaned = body
    .replace(/[\u200C\u200D\uFEFF]/g, '') // strip zero-width chars
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 8000);

  combined += `\n\n---\nFROM: ${from}\nSUBJECT: ${subject}\nBODY: ${cleaned}`;
}

return [{ json: { newsletters: combined } }];
